window.bookSummaryJSON = "<p><i>'Tis the Season</i> is a collection of stories inspired by the beloved characters of Jane Austen in <i>Pride and Prejudice</i>. This collection is comprised of the following nine novellas:</p> <ul> <li>Heart Enough by Amy D’Orazio</li> <li>A Yuletide Dream by Julie Cooper</li> <li>In the Spirit Intended by Jan Ashton</li> <li>Stranded at Pemberley by Jenetta James</li> <li>Christmas at Blackthorn Manor by Lucy Marin</li> <li>Call It Hope by Susan Adriani</li> <li>Welcome Home by Mary Smythe</li> <li>The Pink Daffodil by Elizabeth Rasche</li> <li>Misgivings &amp; Mistletoe by KaraLynne Mackrory</li> </ul>"; 
